package main
import (
    "fmt"
    "time"
)

func slowTask() {
    time.Sleep(2 * time.Second)
    fmt.Println("Slow task finished!")
}

func main() {
    // Start slowTask in the background!
    go slowTask()

    fmt.Println("Main function keeps going...")

    // We must pause main() so it doesn't exit before slowTask finishes!
    time.Sleep(3 * time.Second)
}
